import React, { useState, useEffect } from "react";
import { useApp } from "../App";
import api from "../lib/api";
import { haptic } from "../lib/telegram";

export default function ShopPage() {
  const { user, setUser } = useApp();
  const [skins, setSkins] = useState([]);
  const [loading, setLoading] = useState(true);
  const [busy, setBusy] = useState(null);
  const [msg, setMsg] = useState(null);

  useEffect(() => {
    api.getSkins().then(r => { setSkins(r.skins); setLoading(false); });
  }, []);

  async function buy(skin_id) {
    setBusy(skin_id);
    setMsg(null);
    try {
      const res = await api.buySkin(user.id, skin_id);
      setUser(res.user);
      haptic.notification("success");
      setMsg({ type: "success", text: "Скин куплен! 🎉" });
    } catch (e) {
      haptic.notification("error");
      setMsg({ type: "error", text: e.message });
    } finally {
      setBusy(null);
    }
  }

  async function activate(skin_id) {
    if (user.active_skin === skin_id) return;
    setBusy(skin_id);
    try {
      const res = await api.activateSkin(user.id, skin_id);
      setUser(res.user);
      haptic.impact("light");
    } catch (e) {
      haptic.notification("error");
    } finally {
      setBusy(null);
    }
  }

  if (loading) return <div className="loader"><div className="spinner" /></div>;

  return (
    <div className="page animate-fade">
      <div style={{ marginBottom: 24 }}>
        <div style={{ fontFamily: "Unbounded", fontSize: 22, fontWeight: 700, marginBottom: 4 }}>
          Магазин
        </div>
        <div style={{ color: "var(--text2)", fontSize: 13 }}>
          Баланс: <span className="coins">{user.coins}</span>
        </div>
      </div>

      {msg && (
        <div style={{
          marginBottom: 16, padding: "10px 16px",
          background: msg.type === "success" ? "rgba(34,197,94,0.1)" : "rgba(239,68,68,0.1)",
          border: `1px solid ${msg.type === "success" ? "rgba(34,197,94,0.3)" : "rgba(239,68,68,0.3)"}`,
          borderRadius: 10, color: msg.type === "success" ? "var(--green)" : "var(--red)",
          fontSize: 13, textAlign: "center"
        }}>{msg.text}</div>
      )}

      <div style={{ display: "grid", gridTemplateColumns: "repeat(2, 1fr)", gap: 12 }}>
        {skins.map(skin => {
          const owned = user.owned_skins?.includes(skin.id);
          const active = user.active_skin === skin.id;
          const canAfford = user.coins >= skin.price;

          return (
            <div key={skin.id} style={{
              background: active ? "rgba(124,92,252,0.1)" : "var(--card)",
              border: `1.5px solid ${active ? "var(--accent)" : "var(--border)"}`,
              borderRadius: "var(--radius)", padding: 16, textAlign: "center",
              transition: "all 0.2s"
            }}>
              <div style={{ fontSize: 36, marginBottom: 8 }}>
                <span>{skin.x}</span>
                <span style={{ color: "var(--text3)", margin: "0 4px", fontSize: 18 }}>/</span>
                <span>{skin.o}</span>
              </div>
              <div style={{ fontWeight: 700, marginBottom: 4, fontSize: 14 }}>{skin.name}</div>
              {skin.price === 0
                ? <div className="badge badge-green" style={{ marginBottom: 8 }}>Бесплатно</div>
                : <div className="coins" style={{ marginBottom: 8, display: "block" }}>{skin.price}</div>
              }

              {active ? (
                <div className="badge badge-purple" style={{ fontSize: 11 }}>✓ Активен</div>
              ) : owned ? (
                <button className="btn btn-outline btn-sm btn-block"
                  onClick={() => activate(skin.id)} disabled={busy === skin.id}
                >
                  Надеть
                </button>
              ) : (
                <button
                  className={`btn btn-sm btn-block ${canAfford ? "btn-primary" : "btn-secondary"}`}
                  onClick={() => buy(skin.id)}
                  disabled={busy === skin.id || !canAfford}
                >
                  {busy === skin.id ? "..." : canAfford ? "Купить" : "Мало монет"}
                </button>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}
